 3→import "context"
 4→
 5→type requestIDKey struct{}
 6→
 7→func withRequestID(ctx context.Context, id string) context.Context {
 8→	return context.WithValue(ctx, requestIDKey{}, id)
 9→}
10→
11→func requestIDFromContext(ctx context.Context) string {
12→	id, _ := ctx.Value(requestIDKey{}).(string)
13→	return id
14→}
