  2→
  3→import (
  4→	"context"
  5→	"encoding/json"
  6→	"net/http"
  7→	"net/http/httptest"
  8→	"testing"
  9→
 10→	"github.com/jackc/pgx/v5/pgxpool"
 11→
 12→	"github.com/ketang/kapow/api/internal/handler"
 13→	"github.com/ketang/kapow/api/internal/testdb"
 14→)
 15→
 16→// ─────────────────────────────────────────────────────────────────────────────
 17→// Unit tests — no real DB required
 18→// ─────────────────────────────────────────────────────────────────────────────
 19→
 20→// TestHealth_Degraded verifies that the handler returns HTTP 503 and a
 21→// "degraded" JSON body when the database pool cannot be pinged.
 22→// A pool configured with an unreachable address (port 1 gives ECONNREFUSED
 23→// immediately) is used so the test runs without a live database.
 24→func TestHealth_Degraded(t *testing.T) {
 25→	t.Parallel()
 26→	cfg, err := pgxpool.ParseConfig("postgres://u:p@127.0.0.1:1/db?sslmode=disable&connect_timeout=1")
 27→	if err != nil {
 28→		t.Fatalf("ParseConfig: %v", err)
 29→	}
 30→	pool, err := pgxpool.NewWithConfig(context.Background(), cfg)
 31→	if err != nil {
 32→		t.Fatalf("NewWithConfig: %v", err)
 33→	}
 34→	defer pool.Close()
 35→
 36→	w := httptest.NewRecorder()
 37→	r := httptest.NewRequest(http.MethodGet, "/private/healthcheck", nil)
 38→	handler.Health(pool)(w, r)
 39→
 40→	if w.Code != http.StatusServiceUnavailable {
 41→		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusServiceUnavailable)
 42→	}
 43→
 44→	var body struct {
 45→		Status string `json:"status"`
 46→		DB     struct {
 47→			Status string `json:"status"`
 48→		} `json:"db"`
 49→	}
 50→	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
 51→		t.Fatalf("decode body: %v", err)
 52→	}
 53→	if body.Status != "degraded" {
 54→		t.Errorf("status: got %q, want %q", body.Status, "degraded")
 55→	}
 56→	if body.DB.Status != "error" {
 57→		t.Errorf("db.status: got %q, want %q", body.DB.Status, "error")
 58→	}
 59→}
 60→
 61→// ─────────────────────────────────────────────────────────────────────────────
 62→// Integration tests — require a live database (skipped with -short)
 63→// ─────────────────────────────────────────────────────────────────────────────
 64→
 65→// TestHealth_OK verifies the healthcheck endpoint returns HTTP 200 and a valid
 66→// JSON body when the database is reachable. It uses a containerised PostgreSQL
 67→// database via testdb.New (or TEST_DATABASE_URL if set). The test is skipped
 68→// automatically when run with -short.
 69→func TestHealth_OK(t *testing.T) {
 70→	pool := testdb.New(t)
 71→
 72→	w := httptest.NewRecorder()
 73→	r := httptest.NewRequest(http.MethodGet, "/private/healthcheck", nil)
 74→	handler.Health(pool)(w, r)
 75→
 76→	if w.Code != http.StatusOK {
 77→		t.Errorf("HTTP status: got %d, want %d", w.Code, http.StatusOK)
 78→	}
 79→
 80→	var body struct {
 81→		Status  string `json:"status"`
 82→		Version string `json:"version"`
 83→		DB      struct {
 84→			Status    string `json:"status"`
 85→			LatencyMs int64  `json:"latency_ms"`
 86→		} `json:"db"`
 87→	}
 88→	if err := json.NewDecoder(w.Body).Decode(&body); err != nil {
 89→		t.Fatalf("decode body: %v", err)
 90→	}
 91→	t.Logf("healthcheck response: status=%s version=%s db.status=%s db.latency_ms=%d",
 92→		body.Status, body.Version, body.DB.Status, body.DB.LatencyMs)
 93→
 94→	if body.Status != "ok" {
 95→		t.Errorf("status: got %q, want %q", body.Status, "ok")
 96→	}
 97→	if body.DB.Status != "ok" {
 98→		t.Errorf("db.status: got %q, want %q", body.DB.Status, "ok")
 99→	}
100→	if body.DB.LatencyMs < 0 {
101→		t.Errorf("db.latency_ms should be non-negative, got %d", body.DB.LatencyMs)
102→	}
103→
104→	// Verify the primary search view is populated. An empty dataset_merged
105→	// means the application has no data to serve and should be treated as a
106→	// smoke-test failure.
107→	var count int
108→	if err := pool.QueryRow(context.Background(),
109→		"SELECT COUNT(1) FROM search_base.dataset_merged",
110→	).Scan(&count); err != nil {
111→		t.Fatalf("dataset_merged count query failed: %v", err)
112→	}
113→	t.Logf("dataset_merged row count: %d", count)
114→	if count == 0 {
115→		t.Error("dataset_merged is empty — no institution data available")
116→	}
117→}
