  1→package middleware
  2→
  3→import (
  4→	"log/slog"
  5→	"net/http"
  6→	"strings"
  7→	"sync/atomic"
  8→
  9→	"github.com/ketang/kapow/api/internal/config"
 10→)
 11→
 12→var defaultSensitiveHeaders = map[string]struct{}{
 13→	"Authorization": {},
 14→	"Cookie":        {},
 15→	"Set-Cookie":    {},
 16→	"X-Api-Key":     {},
 17→}
 18→
 19→const redactedValue = "[REDACTED]"
 20→
 21→// HTTPDetailConfig holds the settings for HTTP debug logging.
 22→// It is designed to be swapped at runtime via atomic.Pointer so that
 23→// a future admin endpoint can change debug verbosity without a restart.
 24→type HTTPDetailConfig struct {
 25→	RequestHeaders  string   // "none" | "selected" | "all"
 26→	SelectedHeaders []string // pre-parsed header names
 27→	RedactSensitive bool
 28→	ResponseMode    string // "none" | "headers" | "full"
 29→	BodyMaxBytes    int
 30→}
 31→
 32→// NewHTTPDetailConfig builds an HTTPDetailConfig from the application Config.
 33→func NewHTTPDetailConfig(cfg *config.Config) *HTTPDetailConfig {
 34→	return &HTTPDetailConfig{
 35→		RequestHeaders:  cfg.HTTPDebugRequestHeaders,
 36→		SelectedHeaders: cfg.ParsedSelectedHeaders(),
 37→		RedactSensitive: cfg.HTTPDebugRedactSensitive,
 38→		ResponseMode:    cfg.HTTPDebugResponseMode,
 39→		BodyMaxBytes:    cfg.HTTPDebugBodyMaxBytes,
 40→	}
 41→}
 42→
 43→// HTTPDetail logs request and/or response headers at Debug level.
 44→// The config is read from the atomic pointer on every request, allowing
 45→// hot-reload without restarting the server.
 46→func HTTPDetail(cfgPtr *atomic.Pointer[HTTPDetailConfig]) func(http.Handler) http.Handler {
 47→	return func(next http.Handler) http.Handler {
 48→		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 49→			dc := cfgPtr.Load()
 50→
 51→			// Fast path: no-op when everything is off.
 52→			if dc.RequestHeaders == "none" && dc.ResponseMode == "none" {
 53→				next.ServeHTTP(w, r)
 54→				return
 55→			}
 56→
 57→			// Log request headers before calling next handler.
 58→			if dc.RequestHeaders != "none" {
 59→				attrs := []any{
 60→					"component", "http.detail",
 61→					"request_id", requestIDFromContext(r.Context()),
 62→					"method", r.Method,
 63→					"path", r.URL.Path,
 64→				}
 65→				attrs = append(attrs, buildRequestHeaderAttrs(r.Header, dc.RequestHeaders, dc.SelectedHeaders, dc.RedactSensitive)...)
 66→				slog.DebugContext(r.Context(), "http.detail: request headers", attrs...)
 67→			}
 68→
 69→			// Wrap ResponseWriter when full response logging is requested.
 70→			cw := w
 71→			var bc *bodyCapture
 72→			if dc.ResponseMode == "full" {
 73→				bc = newBodyCapture(w, dc.BodyMaxBytes)
 74→				cw = bc
 75→			}
 76→
 77→			next.ServeHTTP(cw, r)
 78→
 79→			// Log response headers (and optionally body) after handler returns.
 80→			if dc.ResponseMode != "none" {
 81→				attrs := []any{
 82→					"component", "http.detail",
 83→					"request_id", requestIDFromContext(r.Context()),
 84→				}
 85→				attrs = append(attrs, buildResponseHeaderAttrs(cw.Header(), dc.RedactSensitive)...)
 86→				if dc.ResponseMode == "full" && bc != nil {
 87→					attrs = append(attrs,
 88→						"response_body_bytes", bc.captured,
 89→						"response_body_truncated", bc.truncated,
 90→						"response_body", string(bc.buf),
 91→					)
 92→				}
 93→				slog.DebugContext(r.Context(), "http.detail: response", attrs...)
 94→			}
 95→		})
 96→	}
 97→}
 98→
 99→// buildRequestHeaderAttrs converts request headers into slog key-value pairs.
100→func buildRequestHeaderAttrs(h http.Header, mode string, selected []string, redact bool) []any {
101→	var attrs []any
102→	switch mode {
103→	case "all":
104→		for name, values := range h {
105→			val := strings.Join(values, ", ")
106→			if redact && isSensitiveHeader(name) {
107→				val = redactedValue
108→			}
109→			attrs = append(attrs, "req."+name, val)
110→		}
111→	case "selected":
112→		for _, name := range selected {
113→			canonical := http.CanonicalHeaderKey(name)
114→			values := h.Values(canonical)
115→			if len(values) == 0 {
116→				continue
117→			}
118→			val := strings.Join(values, ", ")
119→			if redact && isSensitiveHeader(canonical) {
120→				val = redactedValue
121→			}
122→			attrs = append(attrs, "req."+canonical, val)
123→		}
124→	}
125→	return attrs
126→}
127→
128→// buildResponseHeaderAttrs converts response headers into slog key-value pairs.
129→func buildResponseHeaderAttrs(h http.Header, redact bool) []any {
130→	var attrs []any
131→	for name, values := range h {
132→		val := strings.Join(values, ", ")
133→		if redact && isSensitiveHeader(name) {
134→			val = redactedValue
135→		}
136→		attrs = append(attrs, "resp."+name, val)
137→	}
138→	return attrs
139→}
140→
141→// isSensitiveHeader reports whether the given header name is sensitive.
142→func isSensitiveHeader(name string) bool {
143→	_, ok := defaultSensitiveHeaders[http.CanonicalHeaderKey(name)]
144→	return ok
145→}
146→
147→// bodyCapture wraps an http.ResponseWriter and tees written bytes
148→// into an internal buffer up to a configurable maximum.
149→type bodyCapture struct {
150→	http.ResponseWriter
151→	buf       []byte
152→	captured  int
153→	maxBytes  int
154→	truncated bool
155→}
156→
157→func newBodyCapture(w http.ResponseWriter, maxBytes int) *bodyCapture {
158→	return &bodyCapture{
159→		ResponseWriter: w,
160→		buf:            make([]byte, 0, maxBytes),
161→		maxBytes:       maxBytes,
162→	}
163→}
164→
165→func (bc *bodyCapture) Write(b []byte) (int, error) {
166→	if bc.captured < bc.maxBytes {
167→		remaining := bc.maxBytes - bc.captured
168→		toCapture := len(b)
169→		if toCapture > remaining {
170→			toCapture = remaining
171→			bc.truncated = true
172→		}
173→		bc.buf = append(bc.buf, b[:toCapture]...)
174→		bc.captured += toCapture
175→	} else if !bc.truncated {
176→		bc.truncated = true
177→	}
178→	return bc.ResponseWriter.Write(b)
179→}
180→
181→func (bc *bodyCapture) Unwrap() http.ResponseWriter {
182→	return bc.ResponseWriter
183→}
184→

