 25→func mustNewHMACValidator(t *testing.T, secret string, opts ...jwt.ParserOption) *HMACValidator {
 26→	t.Helper()
 27→	v, err := NewHMACValidator(secret, opts...)
 28→	if err != nil {
 29→		t.Fatalf("NewHMACValidator(%q): %v", secret, err)
 30→	}
 31→	return v
 32→}
 33→
 34→func TestNewHMACValidator_EmptySecret(t *testing.T) {
 35→	t.Parallel()
 36→	_, err := NewHMACValidator("")
 37→	if err == nil {
 38→		t.Fatal("expected error for empty secret")
 39→	}
 40→	if !strings.Contains(err.Error(), "must not be empty") {
 41→		t.Errorf("error = %q, want to contain 'must not be empty'", err.Error())
 42→	}
 43→}
 44→
