10→func TestParseCIDRs(t *testing.T) {
11→	tests := []struct {
12→		name    string
13→		input   string
14→		want    int
15→		wantErr bool
16→	}{
17→		{"single IPv4", "10.0.0.0/8", 1, false},
18→		{"multiple CIDRs", "10.0.0.0/8, 192.168.0.0/16, ::1/128", 3, false},
19→		{"empty string", "", 0, false},
20→		{"whitespace only", "  ,  ", 0, false},
21→		{"invalid CIDR", "not-a-cidr", 0, true},
22→		{"mixed valid and invalid", "10.0.0.0/8, bad", 0, true},
23→		{"localhost defaults", "127.0.0.0/8,::1/128", 2, false},
24→	}
25→	for _, tt := range tests {
26→		t.Run(tt.name, func(t *testing.T) {
27→			nets, err := ParseCIDRs(tt.input)
28→			if (err != nil) != tt.wantErr {
29→				t.Fatalf("ParseCIDRs(%q) error = %v, wantErr %v", tt.input, err, tt.wantErr)
30→			}
31→			if !tt.wantErr && len(nets) != tt.want {
32→				t.Errorf("ParseCIDRs(%q) returned %d nets, want %d", tt.input, len(nets), tt.want)
33→			}
34→		})
35→	}
36→}
