package auth

import (
	"crypto/rsa"
	"errors"
	"fmt"
	"strings"

	"github.com/golang-jwt/jwt/v5"
)

// Claims extends jwt.RegisteredClaims with application-specific fields.
type Claims struct {
	jwt.RegisteredClaims
	Email        string         `json:"email,omitempty"`
	Roles        []string       `json:"roles,omitempty"`
	Role         string         `json:"role,omitempty"`          // Supabase: "authenticated", "anon", etc.
	TeamID       string         `json:"team_id,omitempty"`
	ClientType   string         `json:"client_type,omitempty"`   // web|cli|mobile|desktop
	AppMetadata  map[string]any `json:"app_metadata,omitempty"`  // Supabase: provider info
	UserMetadata map[string]any `json:"user_metadata,omitempty"` // Supabase: user profile data
}

// NormalizedRoles returns a deduplicated union of Roles and the singular Role field.
func (c *Claims) NormalizedRoles() []string {
	seen := make(map[string]struct{}, len(c.Roles)+1)
	var result []string
	for _, r := range c.Roles {
		if _, ok := seen[r]; !ok {
			seen[r] = struct{}{}
			result = append(result, r)
		}
	}
	if c.Role != "" {
		if _, ok := seen[c.Role]; !ok {
			result = append(result, c.Role)
		}
	}
	return result
}

// Provider extracts the authentication provider from AppMetadata.
// Returns an empty string if the provider is not set or is not a string.
func (c *Claims) Provider() string {
	if c.AppMetadata == nil {
		return ""
	}
	p, _ := c.AppMetadata["provider"].(string)
	return p
}

// Validator validates a JWT token string and returns parsed claims.
type Validator interface {
	Validate(tokenString string) (*Claims, error)
}

// HMACValidator validates HS256 tokens using a shared secret.
type HMACValidator struct {
	secret     []byte
	parserOpts []jwt.ParserOption
}

// NewHMACValidator creates a Validator using HS256 with the provided secret.
// It returns an error if the secret is empty or contains only whitespace.
func NewHMACValidator(secret string, opts ...jwt.ParserOption) (*HMACValidator, error) {
	if strings.TrimSpace(secret) == "" {
		return nil, errors.New("auth: HMAC secret must not be empty or whitespace-only")
	}
	return &HMACValidator{
		secret:     []byte(secret),
		parserOpts: opts,
	}, nil
}

// Validate parses and validates an HS256 JWT token string.
func (v *HMACValidator) Validate(tokenString string) (*Claims, error) {
	claims := &Claims{}
	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
		if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
		}
		return v.secret, nil
	}, v.parserOpts...)
	if err != nil {
		return nil, fmt.Errorf("auth: token validation failed: %w", err)
	}
	if !token.Valid {
		return nil, errors.New("auth: token is not valid")
	}
	return claims, nil
}

// RSAValidator validates RS256 tokens using an RSA public key.
type RSAValidator struct {
	publicKey  *rsa.PublicKey
	parserOpts []jwt.ParserOption
}

// NewRSAValidator creates a Validator using RS256 with the provided PEM public key.
func NewRSAValidator(pemPublicKey string, opts ...jwt.ParserOption) (*RSAValidator, error) {
	key, err := jwt.ParseRSAPublicKeyFromPEM([]byte(pemPublicKey))
	if err != nil {
		return nil, fmt.Errorf("auth: failed to parse RSA public key: %w", err)
	}
	return &RSAValidator{
		publicKey:  key,
		parserOpts: opts,
	}, nil
}

// Validate parses and validates an RS256 JWT token string.
func (v *RSAValidator) Validate(tokenString string) (*Claims, error) {
	claims := &Claims{}
	token, err := jwt.ParseWithClaims(tokenString, claims, func(t *jwt.Token) (any, error) {
		if _, ok := t.Method.(*jwt.SigningMethodRSA); !ok {
			return nil, fmt.Errorf("auth: unexpected signing method: %v", t.Header["alg"])
		}
		return v.publicKey, nil
	}, v.parserOpts...)
	if err != nil {
		return nil, fmt.Errorf("auth: token validation failed: %w", err)
	}
	if !token.Valid {
		return nil, errors.New("auth: token is not valid")
	}
	return claims, nil
}

