package middleware

import (
	"errors"
	"io"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"

	"github.com/ketang/kapow/api/internal/auth"
)

// --- Auth middleware tests ---

// mockValidator implements auth.Validator for testing.
type mockValidator struct {
	claims *auth.Claims
	err    error
}

func (m *mockValidator) Validate(_ string) (*auth.Claims, error) {
	return m.claims, m.err
}

func TestAuth_ValidToken(t *testing.T) {
	t.Parallel()
	claims := &auth.Claims{Email: "user@example.com"}
	v := &mockValidator{claims: claims}

	var gotClaims *auth.Claims
	inner := http.HandlerFunc(func(_ http.ResponseWriter, r *http.Request) {
		gotClaims = auth.GetClaims(r.Context())
	})

	handler := Auth(v)(inner)
	req := httptest.NewRequest("GET", "/", nil)
	req.Header.Set("Authorization", "Bearer valid-token")
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusOK {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusOK)
	}
	if gotClaims == nil {
		t.Fatal("expected claims in context")
	}
	if gotClaims.Email != "user@example.com" {
		t.Errorf("email = %q, want %q", gotClaims.Email, "user@example.com")
	}
}

func TestAuth_MissingHeader(t *testing.T) {
	t.Parallel()
	v := &mockValidator{}
	handler := Auth(v)(http.HandlerFunc(func(http.ResponseWriter, *http.Request) {
		t.Error("inner handler should not be called")
	}))

	req := httptest.NewRequest("GET", "/", nil)
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusUnauthorized {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusUnauthorized)
	}
	if !strings.Contains(rr.Header().Get("WWW-Authenticate"), "Bearer") {
		t.Error("expected WWW-Authenticate header with Bearer")
	}
}

func TestAuth_MalformedHeader(t *testing.T) {
	t.Parallel()
	v := &mockValidator{}
	handler := Auth(v)(http.HandlerFunc(func(http.ResponseWriter, *http.Request) {
		t.Error("inner handler should not be called")
	}))

	tests := []struct {
		name   string
		header string
	}{
		{"no bearer prefix", "Token abc123"},
		{"bearer no token", "Bearer "},
		{"just bearer", "Bearer"},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			req := httptest.NewRequest("GET", "/", nil)
			req.Header.Set("Authorization", tt.header)
			rr := httptest.NewRecorder()

			handler.ServeHTTP(rr, req)

			if rr.Code != http.StatusUnauthorized {
				t.Errorf("status = %d, want %d", rr.Code, http.StatusUnauthorized)
			}
		})
	}
}

func TestAuth_InvalidToken(t *testing.T) {
	t.Parallel()
	v := &mockValidator{err: errors.New("auth: token validation failed")}
	handler := Auth(v)(http.HandlerFunc(func(http.ResponseWriter, *http.Request) {
		t.Error("inner handler should not be called")
	}))

	req := httptest.NewRequest("GET", "/", nil)
	req.Header.Set("Authorization", "Bearer bad-token")
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusUnauthorized {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusUnauthorized)
	}
	if !strings.Contains(rr.Header().Get("WWW-Authenticate"), "invalid_token") {
		t.Error("expected WWW-Authenticate header with invalid_token")
	}
}

func TestAuth_MissingHeader_IncludesResourceMetadata(t *testing.T) {
	t.Parallel()
	v := &mockValidator{}
	handler := Auth(v)(http.HandlerFunc(func(http.ResponseWriter, *http.Request) {
		t.Error("inner handler should not be called")
	}))

	req := httptest.NewRequest("GET", "/", nil)
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	wwwAuth := rr.Header().Get("WWW-Authenticate")
	if !strings.Contains(wwwAuth, `resource_metadata="/.well-known/oauth-protected-resource"`) {
		t.Errorf("WWW-Authenticate = %q, want resource_metadata parameter", wwwAuth)
	}
}

func TestAuth_InvalidToken_IncludesResourceMetadata(t *testing.T) {
	t.Parallel()
	v := &mockValidator{err: errors.New("auth: bad token")}
	handler := Auth(v)(http.HandlerFunc(func(http.ResponseWriter, *http.Request) {
		t.Error("inner handler should not be called")
	}))

	req := httptest.NewRequest("GET", "/", nil)
	req.Header.Set("Authorization", "Bearer bad-token")
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	wwwAuth := rr.Header().Get("WWW-Authenticate")
	if !strings.Contains(wwwAuth, `resource_metadata="/.well-known/oauth-protected-resource"`) {
		t.Errorf("WWW-Authenticate = %q, want resource_metadata parameter", wwwAuth)
	}
}

// --- EnsureUser middleware tests ---

// mockUserService is a minimal stand-in for user.Service in unit tests.
// Since user.Service requires a real pgxpool.Pool and the EnsureUser middleware
// is tested via integration tests (auth_integration_test.go), these unit tests
// only verify the no-claims pass-through behaviour.

func TestEnsureUser_NoClaims_PassesThrough(t *testing.T) {
	// EnsureUser with nil service should pass through when no claims are
	// present in context (unauthenticated request).
	called := false
	inner := http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		called = true
		w.WriteHeader(http.StatusOK)
	})

	// Pass nil service — no claims means EnsureUser won't call it.
	handler := EnsureUser(nil)(inner)
	req := httptest.NewRequest("GET", "/", nil)
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if !called {
		t.Error("expected inner handler to be called")
	}
	if rr.Code != http.StatusOK {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusOK)
	}
}

func TestEnsureUser_EmptySubject_PassesThrough(t *testing.T) {
	called := false
	inner := http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		called = true
		w.WriteHeader(http.StatusOK)
	})

	handler := EnsureUser(nil)(inner)
	req := httptest.NewRequest("GET", "/", nil)
	// Set claims with empty subject
	ctx := auth.SetClaims(req.Context(), &auth.Claims{Email: "user@example.com"})
	req = req.WithContext(ctx)
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if !called {
		t.Error("expected inner handler to be called")
	}
	if rr.Code != http.StatusOK {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusOK)
	}
}

// --- OptionalAuth middleware tests ---

func TestOptionalAuth_NoHeader(t *testing.T) {
	v := &mockValidator{}
	var gotClaims *auth.Claims
	var called bool
	inner := http.HandlerFunc(func(_ http.ResponseWriter, r *http.Request) {
		called = true
		gotClaims = auth.GetClaims(r.Context())
	})

	handler := OptionalAuth(v)(inner)
	req := httptest.NewRequest("GET", "/", nil)
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusOK {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusOK)
	}
	if !called {
		t.Error("inner handler should be called")
	}
	if gotClaims != nil {
		t.Error("expected no claims in context for anonymous request")
	}
}

func TestOptionalAuth_ValidToken(t *testing.T) {
	claims := &auth.Claims{Email: "user@example.com"}
	v := &mockValidator{claims: claims}

	var gotClaims *auth.Claims
	inner := http.HandlerFunc(func(_ http.ResponseWriter, r *http.Request) {
		gotClaims = auth.GetClaims(r.Context())
	})

	handler := OptionalAuth(v)(inner)
	req := httptest.NewRequest("GET", "/", nil)
	req.Header.Set("Authorization", "Bearer valid-token")
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusOK {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusOK)
	}
	if gotClaims == nil {
		t.Fatal("expected claims in context")
	}
	if gotClaims.Email != "user@example.com" {
		t.Errorf("email = %q, want %q", gotClaims.Email, "user@example.com")
	}
}

func TestOptionalAuth_InvalidToken(t *testing.T) {
	v := &mockValidator{err: errors.New("auth: token validation failed")}
	handler := OptionalAuth(v)(http.HandlerFunc(func(http.ResponseWriter, *http.Request) {
		t.Error("inner handler should not be called for invalid token")
	}))

	req := httptest.NewRequest("GET", "/", nil)
	req.Header.Set("Authorization", "Bearer bad-token")
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusUnauthorized {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusUnauthorized)
	}
	if !strings.Contains(rr.Header().Get("WWW-Authenticate"), "invalid_token") {
		t.Error("expected WWW-Authenticate header with invalid_token")
	}
}

func TestOptionalAuth_MalformedHeader(t *testing.T) {
	t.Parallel()
	v := &mockValidator{}

	tests := []struct {
		name   string
		header string
	}{
		{"no bearer prefix", "Token abc123"},
		{"bearer no token", "Bearer "},
		{"just bearer", "Bearer"},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			called := false
			inner := http.HandlerFunc(func(_ http.ResponseWriter, _ *http.Request) {
				called = true
			})

			req := httptest.NewRequest("GET", "/", nil)
			req.Header.Set("Authorization", tt.header)
			rr := httptest.NewRecorder()

			handler := OptionalAuth(v)(inner)
			handler.ServeHTTP(rr, req)

			if rr.Code != http.StatusOK {
				t.Errorf("status = %d, want %d", rr.Code, http.StatusOK)
			}
			if !called {
				t.Error("inner handler should be called for malformed (non-bearer) header")
			}
		})
	}
}

// --- RequestID tests ---

func TestRequestID_GeneratesID(t *testing.T) {
	t.Parallel()
	inner := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		id := GetRequestID(r)
		if id == "" {
			t.Error("expected request ID in context")
		}
	})

	handler := RequestID(inner)
	req := httptest.NewRequest("GET", "/", nil)
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Header().Get("X-Request-ID") == "" {
		t.Error("expected X-Request-ID response header")
	}
}

func TestRequestID_PassesThrough(t *testing.T) {
	t.Parallel()
	inner := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		id := GetRequestID(r)
		if id != "my-request-id" {
			t.Errorf("request ID = %q, want %q", id, "my-request-id")
		}
	})

	handler := RequestID(inner)
	req := httptest.NewRequest("GET", "/", nil)
	req.Header.Set("X-Request-ID", "my-request-id")
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Header().Get("X-Request-ID") != "my-request-id" {
		t.Errorf("response X-Request-ID = %q, want %q", rr.Header().Get("X-Request-ID"), "my-request-id")
	}
}

// --- Logging middleware tests ---

func TestLogging(t *testing.T) {
	t.Parallel()
	inner := http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.WriteHeader(http.StatusCreated)
		_, _ = w.Write([]byte("hello"))
	})

	handler := Logging(inner)
	req := httptest.NewRequest("GET", "/test?q=1", nil)
	req.Header.Set("User-Agent", "test-agent")
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusCreated {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusCreated)
	}
	body, _ := io.ReadAll(rr.Body)
	if string(body) != "hello" {
		t.Errorf("body = %q, want %q", string(body), "hello")
	}
}

// --- Recovery middleware tests ---

func TestRecovery_NoPanic(t *testing.T) {
	t.Parallel()
	inner := http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		w.WriteHeader(http.StatusOK)
	})

	handler := Recovery(inner)
	req := httptest.NewRequest("GET", "/", nil)
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusOK {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusOK)
	}
}

func TestRecovery_CatchesPanic(t *testing.T) {
	t.Parallel()
	inner := http.HandlerFunc(func(_ http.ResponseWriter, _ *http.Request) {
		panic("test panic")
	})

	handler := Recovery(inner)
	req := httptest.NewRequest("GET", "/", nil)
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusInternalServerError {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusInternalServerError)
	}
}

// --- responseWriter tests ---

func TestResponseWriter_DefaultStatus(t *testing.T) {
	t.Parallel()
	// When WriteHeader is not called, the default should be 200.
	inner := http.HandlerFunc(func(w http.ResponseWriter, _ *http.Request) {
		_, _ = w.Write([]byte("ok"))
	})

	handler := Logging(inner) // Logging wraps with responseWriter
	req := httptest.NewRequest("GET", "/", nil)
	rr := httptest.NewRecorder()

	handler.ServeHTTP(rr, req)

	if rr.Code != http.StatusOK {
		t.Errorf("status = %d, want %d", rr.Code, http.StatusOK)
	}
}

package handler

import (
	"context"
	"encoding/json"
	"log/slog"
	"net/http"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ketang/kapow/api/internal/version"
)

type dbStatus struct {
	Status    string `json:"status"`
	LatencyMs int64  `json:"latency_ms"`
}

type healthResponse struct {
	Status  string   `json:"status"`
	Version string   `json:"version"`
	DB      dbStatus `json:"db"`
}

// Health returns a JSON health check response including DB connectivity and latency.
func Health(pool *pgxpool.Pool) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		ctx, cancel := context.WithTimeout(r.Context(), 2*time.Second)
		defer cancel()

		dbStat := dbStatus{Status: "ok"}
		start := time.Now()
		if err := pool.Ping(ctx); err != nil {
			dbStat.Status = "error"
			slog.WarnContext(r.Context(), "healthcheck: database ping failed",
				"error", err,
				"latency_ms", time.Since(start).Milliseconds(),
			)
		}
		dbStat.LatencyMs = time.Since(start).Milliseconds()

		resp := healthResponse{
			Status:  "ok",
			Version: version.Version,
			DB:      dbStat,
		}

		w.Header().Set("Content-Type", "application/json")
		if dbStat.Status != "ok" {
			w.WriteHeader(http.StatusServiceUnavailable)
			resp.Status = "degraded"
		}
		_ = json.NewEncoder(w).Encode(resp)
	}
}

